let mocha = require('mocha');
let assert = require('assert');
let pull_stream = require('pull-stream');

describe('test pull_stream', function() {
    it('should drain all values from a stream', function(done) {
        let values = [];
        let source = pull_stream.values([1, 2, 3, 4, 5]);
        let drain = pull_stream.drain(
            function(data) {
                values.push(data);
            },
            function(err) {
                assert.strictEqual(err, null);
                assert.deepEqual(values, [1, 2, 3, 4, 5]);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should handle empty streams', function(done) {
        let values = [];
        let source = pull_stream.values([]);
        let drain = pull_stream.drain(
            function(data) {
                values.push(data);
            },
            function(err) {
                assert.strictEqual(err, null);
                assert.deepEqual(values, []);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should stop draining when op returns false', function(done) {
        let values = [];
        let source = pull_stream.values([1, 2, 3, 4, 5]);
        let drain = pull_stream.drain(
            function(data) {
                values.push(data);
                return data < 3; // Stop when we reach 3
            },
            function(err) {
                assert.strictEqual(err, null);
                assert.deepEqual(values, [1, 2, 3]);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should handle errors from source', function(done) {
        let testError = new Error('test error');
        let source = function(end, cb) {
            if (end) return cb(end);
            cb(testError);
        };
        let drain = pull_stream.drain(
            function(data) {
                // Should not be called
                assert.fail('op should not be called on error');
            },
            function(err) {
                assert.strictEqual(err, testError);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should work without op function', function(done) {
        let source = pull_stream.values([1, 2, 3]);
        let drain = pull_stream.drain(
            null,
            function(err) {
                assert.strictEqual(err, null);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should handle abort', function(done) {
        let values = [];
        let source = pull_stream.values([1, 2, 3, 4, 5]);
        let drain = pull_stream.drain(
            function(data) {
                values.push(data);
                if (data === 2) {
                    drain.abort();
                }
            },
            function(err) {
                assert.strictEqual(err, null);
                assert.deepEqual(values, [1, 2]);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should handle abort with error', function(done) {
        let testError = new Error('abort error');
        let source = pull_stream.values([1, 2, 3, 4, 5]);
        let drain = pull_stream.drain(
            function(data) {
                if (data === 2) {
                    drain.abort(testError);
                }
            },
            function(err) {
                assert.strictEqual(err, testError);
                done();
            }
        );
        pull_stream(source, drain);
    });

    it('should warn and throw when no done callback is provided and error occurs', function(done) {
        let testError = new Error('test error');
        let source = function(end, cb) {
            if (end) return cb(end);
            cb(testError);
        };

        // Capture console.warn
        let originalWarn = console.warn;
        let warnCalled = false;
        console.warn = function() {
            warnCalled = true;
        };

        let drain = pull_stream.drain(function(data) {
            // Should not be called
        }); // No done callback

        // Capture the thrown error
        process.once('uncaughtException', function(err) {
            console.warn = originalWarn;
            assert.strictEqual(err, testError);
            assert.strictEqual(warnCalled, true);
            done();
        });

        pull_stream(source, drain);
    });
});
